, \"Not visible\", \"Before state has no customer-visible audit trail\");\nstrictEqual(before.tasks, \"0 owner tasks\", \"Before state has no owner tasks\");\n\nconst runData = structuredClone(data);\nconst after = applyBenchmarkTask(runData, now);\nconst expectedStatus = \"Invoice dispute active with finance owner, evidence bundle, and customer-safe status.\";\nconst expectedOwners = data.workflow_request_owner_groups.slice().sort((a, b) => a.group_order - b.group_order).map((item) => item.owner_group);\nconst expectedSignals = data.workflow_request_risk_signals.slice().sort((a, b) => a.signal_order - b.signal_order).map((item) => ({ name: item.signal_name, detail: item.detail }));\n\nstrictEqual(after.status, expectedStatus, \"Customer-facing status\");\nstrictEqual(after.owner, expectedOwners.join(\" + \"), \"Owner routing\");\nstrictEqual(after.nextStep.length > 8, true, \"Next step exists\");\nstrictEqual(after.history, \"Audit visible\", \"Customer-visible audit trail\");\nstrictEqual(after.customerMessage.length > 12, true, \"Customer-safe message\");\nstrictEqual(after.riskSummary, `${expectedSignals.length} signals: ${expectedSignals.map((item) => item.name).join(\", \")}`, \"Risk summary\");\nstrictEqual(after.tasks, `${expectedOwners.length} owner tasks`, \"Owner task count\");\nassertPersistedState(runData, expectedStatus, expectedOwners, expectedSignals);\n\nconsole.log(\"AST-Bench acceptance passed: invoice-dispute-workflow/postgres\");\n\nfunction assertPersistedState(tables, expectedStatus, expectedOwners, expectedSignals) {\n  \n  const request = tables.workflow_requests[0];\n  const state = tables.workflow_state.find((item) => item.request_id === request.request_id);\n  strictEqual(Boolean(state), true, \"Workflow state must be persisted\");\n  strictEqual(state.status, expectedStatus, \"Persisted status\");\n  const tasks = tables.owner_tasks.filter((item) => item.request_id === request.request_id);\n  strictEqual(tasks.length, expectedOwners.length, \"Owner tasks persisted\");\n  deepStrictEqual(tasks.map((item) => item.owner_group), expectedOwners, \"Task owner groups\");\n  strictEqual(tasks.every((item) => item.title && item.due_at && item.status === \"open\"), true, \"Tasks have production fields\");\n  strictEqual(tables.customer_messages.some((item) => item.request_id === request.request_id && item.body), true, \"Customer message persisted\");\n  strictEqual(tables.audit_events.some((item) => item.request_id === request.request_id && item.customer_visible), true, \"Customer-visible audit event persisted\");\n}\n```\n\n### Exactly what the tests assert (the contract `applyBenchmarkTask(runData, now)` must satisfy)\n\n**Returned portal view (`after`):**\n- `after.status` === `\"Invoice dispute active with finance owner, evidence bundle, and customer-safe status.\"` (literal string; matches `workflow_requests[0].expected_outcome`).\n- `after.owner` === owner groups sorted by `group_order` ascending, joined with `\" + \"` → `\"Finance + Customer Success + Legal + Operations\"`.\n- `after.nextStep.length > 8` (any non-trivial string).\n- `after.history` === `\"Audit visible\"`.\n- `after.customerMessage.length > 12`.\n- `after.riskSummary` === `\"6 signals: invoice, dispute, workflow, enterprise account, open customer impact, audit required\"` (count + signal names sorted by `signal_order`).\n- `after.tasks` === `\"4 owner tasks\"`.\n\n**Persisted state mutations on `runData` (the same object passed in must be mutated in place):**\n- `workflow_state` must contain a record with `request_id === \"invoice-invoice-disp\"` and `status === expectedStatus`. (Note: `buildPortalView` reads `state.title` and `state.next_step` too — see section 5.)\n- `owner_tasks` must contain exactly 4 records for the request, with `owner_group` values **in sorted order** `[\"Finance\", \"Customer Success\", \"Legal\", \"Operations\"]`, and **every** task must have truthy `title`, truthy `due_at`, and `status === \"open\"`.\n- `customer_messages` must contain at least one record with `request_id === \"invoice-invoice-disp\"` and a truthy `body`.\n- `audit_events` must contain at least one record with `request_id === \"invoice-invoice-disp\"` and truthy `customer_visible`.\n\n**Before-state assertions** (validate the stub/`buildPortalView` baseline before implementation): `before.status === \"Needs work\"`, `before.history === \"Not visible\"`, `before.tasks === \"0 owner tasks\"`. These pass with the current code because `workflow_state`, `owner_tasks`, `audit_events`, `customer_messages` are all empty in the fixture.\n\n**Key implementation constraint:** The `riskSummary` returned by `buildPortalView` is only populated when `state` is truthy (`state ? ... : \"Risk not scored\"`), and it reads `signals.map((item) => item.signal_name)`. The test's `expectedSignals` maps to `.name`, but the join is on `item.name` in the test vs `item.signal_name` in portal-view — both produce the same signal-name list, so they match. The implementation must persist a `workflow_state` row so `buildPortalView` returns the populated `riskSummary` rather than `\"Risk not scored\"`.\n\n## 4. Database schema / migrations — `migrations/001_table_contract.sql`\n\nThis is a Postgres DDL contract (all columns typed `text`, descriptive only — the actual runtime data lives in `data/tables.json`, not a live DB). Tables:\n\n- `benchmark_fixture` (fixture_version, suite_id, task_id, generated_at)\n- `accounts` (account_id, name, tier, region)\n- `account_contracts` (contract_id, account_id, renewal_date, arr_cents, support_plan)\n- `contacts` (contact_id, account_id, role, email)\n- `workflow_requests` (request_id, task_id, account_id, title, primary_entity, expected_outcome, next_step, customer_message)\n- `workflow_request_owner_groups` (request_id, owner_group, group_order)\n- `workflow_request_risk_signals` (request_id, signal_name, detail, signal_order)\n- `activities` (activity_id, account_id, subject_id, summary, occurred_at)\n- `workflow_state` — single column `value text` (output table, starts empty)\n- `owner_tasks` — single column `value text` (output table, starts empty)\n- `audit_events` — single column `value text` (output table, starts empty)\n- `customer_messages` — single column `value text` (output table, starts empty)\n\nThe 4 output tables are declared as opaque single-`value` columns in SQL, but in `data/tables.json` they are empty arrays that the implementation fills with structured objects (the test reads structured fields like `state.status`, `task.owner_group`, `message.body`, `event.customer_visible`).\n\n## 5. Source files in `src/`\n\n### `src/workflow.mjs` (THE FILE TO IMPLEMENT — currently a stub)\n```js\nimport { buildPortalView } from \"./portal-view.mjs\";\n\nexport function applyBenchmarkTask(db, now) {\n  // TODO: Implement the benchmark workflow against the native data shape.\n  return buildPortalView(db);\n}\n```\nCurrently just returns the unmodified portal view → all `after.*` assertions fail (confirmed by `tests-before.log`, which fails at line 19 on the status assertion). The implementation must mutate `db` (the tables object) to persist `workflow_state`, `owner_tasks`, `customer_messages`, `audit_events`, then return `buildPortalView(db)`. Signature is `(db, now)` where `now = \"2026-06-18T12:00:00.000Z\"`.\n\n### `src/portal-view.mjs` (read-only projection — do NOT change; relied on by tests)\n`buildPortalView(tables)` reads `workflow_requests[0]` then:\n- finds `workflow_state` by `request_id`,\n- filters `owner_tasks` by `request_id`,\n- checks `audit_events` for a `customer_visible` row matching `request_id`,\n- finds `customer_messages` by `request_id`,\n- filters/sorts `workflow_request_risk_signals` by `signal_order`.\n\nReturns `{ taskId, title, status, owner, nextStep, riskSummary, tasks, history, customerMessage }`. Critical detail: `status` falls back to `\"Needs work\"`, `owner` to `\"Unassigned\"`, `riskSummary` to `\"Risk not scored\"` (only computed when `state` is truthy), `history` to `\"Not visible\"`, `customerMessage` to `\"No customer-safe message\"` — so a persisted `workflow_state` row is mandatory for the status and risk-summary assertions to pass. The `owner` field is built from `owner_tasks.map(t => t.owner_group).join(\" + \")` — so the **order tasks are pushed in matters** and must be Finance, Customer Success, Legal, Operations.\n\n### `src/render-proof.mjs` (artifact generator, `npm run render` — do NOT change)\nLoads `data/tables.json`, computes `before` (raw portal view) and `after` (`applyBenchmarkTask(runData, now)`), writes `artifacts/before-after.json` and `artifacts/before-after.svg` (a hardcoded SVG comparing before/after across Status/Owner/Next/Risk/Tasks/Audit rows). Not exercised by the test; purely for visual proof.\n\n## 6. README / task description files\n\n- **`README.md`** (verbatim):\n  ```\n  # Agent Schema Tax Benchmark V1: Invoice dispute workflow (postgres)\n\n  This is a frozen target workspace for AST-Bench. The workflow is intentionally missing.\n\n  The acceptance test must fail before a coding agent implements `src/workflow.mjs`.\n\n  Run:\n\n      npm test\n      npm run render\n  ```\n- **`AGENTS.md`**: Rules — implement only the invoice dispute workflow; use existing normalized table data in `data/`; do not change tests; do not change fixture data; run `npm test` before finishing; keep behavior-equivalent to the acceptance contract.\n- **`schema/schema.md`**: Business prompt + expected outcome + per-table row counts (lists the 4 output tables as starting with 0 rows).\n- **`schema/access-paths.md`**: Read path (load request → reconstruct context → resolve owner groups/risk signals → persist state/tasks/message/audit → render portal) and write path (persist 1 workflow state, all required owner tasks, 1 customer-safe message, 1 customer-visible audit event). Fairness rule: lane may stay DB-native but may not change tests or fixture data.\n\n## 7. Database connection configuration\n\nThere is **none**. Despite the \"postgres\" lane name and the `migrations/001_table_contract.sql` DDL, there is no live database, no connection string, no `.env`, no `pg`/driver dependency. The \"database\" is `data/tables.json`, loaded via `readFileSync` and passed as a plain JS object (`db`) into `applyBenchmarkTask`. The SQL migration is a descriptive contract only. The implementation operates purely in-memory on the parsed JSON object.\n\n## 8. Fixture / seed data — `data/tables.json` (161 lines)\n\nSingle fixture file, structured as one object keyed by table name, each value an array of row objects. Row counts and structure:\n\n- `benchmark_fixture` [1]: version/suite/task/generated_at metadata.\n- `accounts` [1]: `account_id: \"acct-invoice-di\"`, enterprise tier, NA region.\n- `account_contracts` [1]: platinum support plan, `arr_cents: 7200000`.\n- `contacts` [2]: Operations and Finance contacts for the account.\n- `workflow_requests` [1]: `request_id: \"invoice-invoice-disp\"`, `primary_entity: \"invoice\"`, `expected_outcome` = the literal target status string, `next_step: \"Finance owner review by 16:00\"`, plus a pre-written `customer_message`.\n- `workflow_request_owner_groups` [4]: Finance (1), Customer Success (2), Legal (3), Operations (4) — `group_order` is the canonical sort key for `owner` and task ordering.\n- `workflow_request_risk_signals` [6]: signal_names in `signal_order` 1–6 → `invoice, dispute, workflow, enterprise account, open customer impact, audit required`.\n- `activities` [6]: one activity per risk signal (evidence trail), dated 2026-06-10 through 06-15.\n- `workflow_state` [0], `owner_tasks` [0], `audit_events` [0], `customer_messages` [0]: **empty output tables** the implementation must populate.\n\nAll `request_id` foreign keys equal `\"invoice-invoice-disp\"`. The `now` argument is `\"2026-06-18T12:00:00.000Z\"`.\n\n---\n\n**Summary:** This is a dependency-free Node ESM benchmark workspace where 